import mysql.connector

def import_data_to_mysql():
    # Get file path from user input
    file_path = input("Enter the full path of the CSV file to import: ")

    # Establish a connection to MySQL server
    try:
        conn = mysql.connector.connect(
            host='your_host',
            user='your_user',
            password='your_password',
            database='your_database',
            allow_local_infile=True  # Enable local infile in connector
        )

        cursor = conn.cursor()

        # Load data from file into MySQL table
        try:
            with open(file_path, 'r') as file:
                # Ensure the file is readable and accessible
                cursor.execute("LOAD DATA INFILE '{}' INTO TABLE your_table "
                               "FIELDS TERMINATED BY ',' ENCLOSED BY '\"' "
                               "LINES TERMINATED BY '\n' "
                               "IGNORE 1 ROWS;".format(file_path))
            conn.commit()
            print("Data imported successfully.")
        except Exception as e:
            print("Error during data import:", str(e))
        finally:
            cursor.close()

    except mysql.connector.Error as err:
        print("MySQL connection error:", err)
    finally:
        if conn.is_connected():
            conn.close()

if __name__ == "__main__":
    import_data_to_mysql()